    dp = [[0] * n for _ in range(n)]
    for i in range(n - 1, -1, -1):
        for j in range(i, n):
            if i == j:
                dp[i][j] = 1
            elif s[i] == s[j]:
                if j - i > 1:
                    dp[i][j] = 2 + dp[i + 1][j - 1]
                else:
                    dp[i][j] = 2
            else:
                dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])
    res = dp[0][n - 1]
    for i in range(n):
        for j in range(i, n):
            temp = s[:i] + s[i + 1:j] + s[j + 1:]
            if temp == temp[::-1]:
                res = max(res, n - (j - i + 1))
    return min(res + k, n)

