def longest_palindrome(s: str, k: int) -> int:
    def is_palindrome(i, j, k):
        while i < j:
            if s[i] != s[j]:
                if k == 0:
                    return False
                k -= 1
            i += 1
            j -= 1
        return True

    max_length = 0
    for i in range(len(s)):
        for j in range(i, len(s)):
            if is_palindrome(i, j, k):
                max_length = max(max_length, j - i + 1)
    return max_length

