def longest_palindrome_two(s, k):
    def expand_around_center(s, left, right, k):
        while left >= 0 and right < len(s) and (s[left] == s[right] or k > 0):
            if s[left] != s[right]:
                k -= 1
            left -= 1
            right += 1
        return right - left - 1, k

    max_length = 0
    for i in range(len(s)):
        length, k_remaining = expand_around_center(s, i, i, k)
        max_length = max(max_length, length)
        length, k_remaining = expand_around_center(s, i, i + 1, k)
        max_length = max(max_length, length)
    return max_length

