    for char in s:
        char_count[char] = char_count.get(char, 0) + 1
    pairs = sum(count // 2 for count in char_count.values())
    return 2 * pairs + (1 if pairs * 2 < len(s) and k >= len(s) - pairs * 2 else 0) + 2 * min(k, len(s) - pairs * 2)

